// Build the markdown file binary + a clean filename
const item = $input.first();
const body = item.json.body || item.json;
const markdown = body.markdown || '# (empty submission)';
const submittedAt = body.submittedAt || new Date().toISOString();
const stevenEmail = body.email || '';
const legalName = (body.state && body.state.s13 && body.state.s13.legalName) || 'Exceptional Comfort Services';

const now = new Date();
const pad = (n) => String(n).padStart(2, '0');
const stamp = `${now.getFullYear()}-${pad(now.getMonth()+1)}-${pad(now.getDate())}-${pad(now.getHours())}${pad(now.getMinutes())}`;
const fileName = `ECS-Website-Intake-${stamp}.md`;

const binary = await this.helpers.prepareBinaryData(
  Buffer.from(markdown, 'utf-8'),
  fileName,
  'text/markdown'
);

return [{
  json: {
    fileName,
    submittedAt,
    stevenEmail,
    legalName,
    markdown
  },
  binary: { data: binary }
}];

